import { Injectable, inject } from '@angular/core';
import { GameInfoResponse } from './api.models';
import { catchError, firstValueFrom } from 'rxjs';
import { API_URL, AuthService } from './auth';
import { HttpClient, HttpResponseBase } from '@angular/common/http';

@Injectable({
  providedIn: 'root',
})
export class ApiService {
  private readonly authService = inject(AuthService);
  private readonly httpClient = inject(HttpClient);

  public async getGameInfo(): Promise<GameInfoResponse> {
    return firstValueFrom(
      this.httpClient.post<GameInfoResponse>(`${API_URL}/game/info`, {}).pipe(
        catchError((error: HttpResponseBase) => {
          if (error.status === 401) {
            this.authService.logout();
          }
          throw error;
        }),
      ),
    );
  }
}
