import { Component, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { WeatherComponent } from '../../components/weather/weather';
import { HeaderComponent } from '../../components/dump/header/header';
import { ButtonComponent } from '../../components/dump/button/button';
import { AuthService } from '../../services/api/auth';
import { SidePanelComponent } from '../../components/dump/side-panel/side-panel';
import { RouterLink } from '@angular/router';
import { ApiService } from '../../services/api/api';
import { MinimapComponent } from '../../components/smart/minimap/minimap';
import { GameMapComponent } from '../../components/smart/game-map/game-map';
import { DayService } from '../../services/day';
import { MAX_GAME_ZOOM, MIN_GAME_ZOOM } from '../../services/_params';

@Component({
  selector: 'game-page',
  imports: [CommonModule, MinimapComponent, WeatherComponent, HeaderComponent, ButtonComponent, SidePanelComponent, RouterLink, GameMapComponent],
  standalone: true,
  templateUrl: './game.html',
})
export class GamePage {
  protected readonly authService = inject(AuthService);
  private readonly dayService = inject(DayService);
  private readonly apiService = inject(ApiService);

  protected readonly maxZoom = MAX_GAME_ZOOM;
  protected readonly minZoom = MIN_GAME_ZOOM;

  protected readonly seed = signal<number | undefined>(undefined);
  protected readonly sizeX = signal<number>(500);
  protected readonly sizeY = signal<number>(500);

  public constructor() {
    void this.getGameInfo();
  }

  private async getGameInfo() {
    const data = await this.apiService.getGameInfo();
    const { seed, sizeX, sizeY } = data.map;
    this.sizeX.set(sizeX);
    this.sizeY.set(sizeY);
    this.seed.set(seed);
    this.dayService.timeDiff.set(data.time - Date.now());
  }
}
